const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // ── NORMALIZE LinkedIn URL ──
  let rawUrl = (d.source_url || '').trim();

  // Step 1: lowercase everything
  let normalized = rawUrl.toLowerCase();

  // Step 2: remove protocol variations
  normalized = normalized
    .replace(/^https?:\/\//i, '')
    .replace(/^http:\/\//i, '');

  // Step 3: remove www.
  normalized = normalized.replace(/^www\./, '');

  // Step 4: ensure starts with linkedin.com
  if (!normalized.startsWith('linkedin.com')) {
    // Not a LinkedIn URL — flag it
    results.push({
      json: {
        ...d,
        normalized_url: null,
        normalization_status: 'invalid_url',
        skip: true
      }
    });
    continue;
  }

  // Step 5: remove trailing slash
  normalized = normalized.replace(/\/$/, '');

  // Step 6: rebuild clean URL
  const cleanUrl = 'https://www.' + normalized + '/';

  // Step 7: extract username
  const username = cleanUrl
    .replace('https://www.linkedin.com/in/', '')
    .replace('/', '');

  // Step 8: final normalized form
  const finalUrl = 'https://www.linkedin.com/in/' +
    username + '/';

  results.push({
    json: {
      ...d,
      normalized_url: finalUrl,
      linkedin_username: username,
      normalization_status: 'normalized',
      skip: false,
      updated_at: new Date().toISOString()
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Generate learner_id if missing
  let learnerId = d.learner_id;

  if (!learnerId || learnerId === '') {
    // Promote valid URL record from S2 to S3
    // Generate ID from username
    const username = (d.linkedin_username ||
      d.normalized_url
        .replace('https://www.linkedin.com/in/', '')
        .replace('/', '')
    );
    learnerId = 'LRN-' + 
      username.toUpperCase()
        .replace(/[^A-Z0-9]/g, '')
        .substring(0, 8) +
      '-' + Date.now().toString().slice(-4);
  }

  results.push({
    json: {
      ...d,
      learner_id: learnerId,
      id_repaired: !d.learner_id,
      stage: 'S3'
    }
  });
}

return results;

const items = $input.all();
const results = [];

// Group by normalized_url
const groups = {};
for (const item of items) {
  const url = item.json.normalized_url;
  if (!groups[url]) groups[url] = [];
  groups[url].push(item.json);
}

for (const [url, records] of Object.entries(groups)) {
  // Sort by created_at — oldest is primary
  records.sort((a, b) =>
    new Date(a.created_at) - new Date(b.created_at)
  );

  const primary = records[0];

  for (let i = 0; i < records.length; i++) {
    const rec = records[i];
    const isPrimary = i === 0;

    results.push({
      json: {
        ...rec,
        is_duplicate: !isPrimary,
        primary_record_id: primary.record_id,
        duplicate_group: url,
        stage: 'S4',
        updated_at: new Date().toISOString()
      }
    });
  }
}

return results;

